#' Wrapper function to create an RTMB_Model instance
#'
#' @param data A list of data used for modeling.
#' @param parameters A list (or alist) of parameters.
#' @param log_prob A function or code generated by model_code().
#' @param transformed An optional function OR a list of expressions.
#' @param generate An optional function for generated quantities.
rtmb_model <- function(data, parameters, model,
                       transformed = NULL,
                       generate = NULL) {

  # 1. parameters の評価 (Pなどの変数展開)
  build_par_list <- function(dat) {
    eval_env <- list2env(dat, parent = parent.frame())
    lapply(parameters, function(x) {
      if (typeof(x) %in% c("language", "symbol")) eval(x, envir = eval_env) else x
    })
  }
  evaluated_par_list <- build_par_list(data)

  raw_transformed <- substitute(transformed)
  if (!is.null(raw_transformed) && !is.function(transformed)) {
    transformed <- eval(bquote(transformed_code(.(raw_transformed), env = parent.frame())))
  }

  raw_generate <- substitute(generate)
  if (!is.null(raw_generate) && !is.function(generate)) {
    generate <- eval(bquote(transformed_code(.(raw_generate), env = parent.frame())))
  }

  model_instance <- RTMB_Model$new(
    data         = data,
    par_list     = evaluated_par_list,
    log_prob     = model,
    transform    = transformed,
    generate     = generate
  )

  return(model_instance)
}
#' Model Code Wrapper for RTMB
#'
#' @param expr A block of code containing model description.
#' @param env Environment to assign to the generated function.
#' @return A standard R function object taking (dat, par).
#' @export
model_code <- function(expr, env = parent.frame()) {
  raw_expr <- substitute(expr)

  # 式を再帰的に走査し、`~` の記述を書き換える
  rewrite_formula <- function(x) {
    if (is.call(x)) {
      if (identical(x[[1]], as.name("~"))) {
        target <- x[[2]]
        dist_call <- x[[3]]
        dist_name <- as.character(dist_call[[1]])
        dist_args <- as.list(dist_call[-1])

        name_lpdf <- paste0(dist_name, "_lpdf")
        name_lpmf <- paste0(dist_name, "_lpmf")

        # 環境に存在する方を優先的に採用
        if (exists(name_lpdf, mode = "function", envir = env)) {
          actual_name <- name_lpdf
        } else if (exists(name_lpmf, mode = "function", envir = env)) {
          actual_name <- name_lpmf
        } else {
          actual_name <- name_lpdf # デフォルト
        }

        # lp <- lp + actual_name(target, args...) の純粋な構文木を作成
        new_call <- as.call(c(
          as.name("<-"),
          as.name("lp"),
          as.call(c(
            as.name("+"),
            as.name("lp"),
            as.call(c(as.name(actual_name), target, dist_args))
          ))
        ))
        return(new_call)
      }
      x[] <- lapply(x, rewrite_formula)
    }
    return(x)
  }

  processed_expr <- rewrite_formula(raw_expr)

  # ブロック {} の場合は中身を展開してフラットにする
  if (is.call(processed_expr) && identical(processed_expr[[1]], as.name("{"))) {
    expr_elements <- as.list(processed_expr)[-1]
  } else {
    expr_elements <- list(processed_expr)
  }

  # 関数の中身（ボディ）を構築: { getAll(dat, par); lp <- 0; ... ; return(lp) }
  body_list <- c(
    list(as.name("{")),
    quote(getAll(dat, par)),
    quote(lp <- 0),
    expr_elements,
    quote(return(lp))
  )
  body_expr <- as.call(body_list)

  # 引数リスト `(dat, par)` を作成
  args <- as.pairlist(alist(dat = , par = ))

  # call("function", args, body) で関数定義の構文木を作り、evalで実体化
  fn_expr <- call("function", args, body_expr)
  log_prob_fn <- eval(fn_expr, envir = env)

  return(log_prob_fn)
}
#' Transformed Code Wrapper for RTMB
#'
#' @param expr A block of code containing calculations for transformed parameters.
#' @param env Environment to assign to the generated function.
#' @return A function taking (dat, par) that returns a named list.
#' @export
transformed_code <- function(expr, env = parent.frame()) {
  raw_expr <- substitute(expr)

  # 1. コードブロックから「定義されている変数名」を抽出するヘルパー
  find_assignments <- function(x) {
    if (is.call(x)) {
      if (identical(x[[1]], as.name("<-")) || identical(x[[1]], as.name("="))) {
        # 左辺がシンボル（単一変数）の場合のみ抽出
        if (is.name(x[[2]])) return(as.character(x[[2]]))
      }
      return(unique(unlist(lapply(as.list(x), find_assignments))))
    }
    return(NULL)
  }

  defined_vars <- find_assignments(raw_expr)

  # 2. 中括弧 {} の中身をフラットにする
  if (is.call(raw_expr) && identical(raw_expr[[1]], as.name("{"))) {
    expr_elements <- as.list(raw_expr)[-1]
  } else {
    expr_elements <- list(raw_expr)
  }

  # 3. return(list(var1 = var1, ...)) の形を作成
  ret_list_args <- lapply(defined_vars, as.name)
  names(ret_list_args) <- defined_vars
  ret_call <- as.call(c(list(as.name("list")), ret_list_args))

  # 4. 関数ボディの構築
  body_list <- c(
    list(as.name("{")),
    quote(getAll(dat, par)),
    expr_elements,
    list(as.call(list(as.name("return"), ret_call)))
  )
  body_expr <- as.call(body_list)

  # 5. 関数オブジェクトの生成
  args <- as.pairlist(alist(dat = , par = ))
  fn_expr <- call("function", args, body_expr)
  fn <- eval(fn_expr, envir = env)

  return(fn)
}
